import Security

// Function to add a new item to Keychain
func addKeychainItem(_ key: String, value: String) {
    let query: [String: Any] = [kSecClass as String: kSecClassGenericPassword,
                               kSecAttrAccount as String: key,
                               kSecAttrService as String: "com.yourcompany.yourapp",
                               kSecValueData as String: value.data(using: .utf8)!]

    let status = SecItemAdd(query as CFDictionary, nil)

    if status != errSecSuccess {
        print("Failed to add item to Keychain")
    }
}

// Function to retrieve an item from Keychain
func getKeychainItem(_ key: String) -> String? {
    let query: [String: Any] = [kSecClass as String: kSecClassGenericPassword,
                               kSecAttrAccount as String: key,
                               kSecAttrService as String: "com.yourcompany.yourapp",
                               kSecReturnData as String: kCFBooleanTrue]

    var item: CFTypeRef?
    let status = SecItemCopyMatching(query as CFDictionary, &item)

    if status == errSecSuccess {
        if let data = item as? Data {
            return String(data: data, encoding: .utf8)
        }
    }

    return nil
}

// Example usage:
let apiKey = "your_api_key"
let key = "api_key"

addKeychainItem(key, value: apiKey)

if let storedApiKey = getKeychainItem(key) {
    print("Stored API Key: \(storedApiKey)")
} else {
    print("Failed to retrieve API Key")
}
```

