// Define a struct to hold your configuration data
struct Configuration: Codable {
    let apiKey: String
    let apiSecret: String
}

// Function to write the configuration to a file
func writeConfiguration(_ configuration: Configuration, to file: URL) {
    do {
        let data = try PropertyListEncoder().encode(configuration)
        try data.write(to: file)
    } catch {
        print("Failed to write configuration: \(error)")
    }
}

// Function to read the configuration from a file
func readConfiguration(from file: URL) -> Configuration? {
